msg.payload = {
    door: "ON",
    temperature: 33,
    humidity_percentage: 45
};

return msg;

const alarm = msg.payload;

const device = alarm.originatorName;

let customer;

if (device.includes("01")) {
  customer = "gas-station-01";
} else if (device.includes("02")) {
  customer = "gas-station-02";
} else if (device.includes("03")) {
  customer = "gas-station-03";
} else {
  customer = "unknown";
}

msg.customer = customer;

const deviceName = alarm.originatorName || "unknown_device";

// timestamp
const now = new Date();
const ts = now.toISOString().replace(/[:.]/g, "-");

// filename
const deviceClean = deviceName.replace(/\s+/g, "_");
const filename = `alarm_${deviceClean}_${ts}.json`;

// local path
const localPath = `/data/${filename}`;

// content
const content = JSON.stringify(alarm, null, 2);

// File node
msg.payload = content;
msg.filename = localPath;

// MinIO
msg.filePath = localPath;
msg.objectName = filename;

// metadata
msg.metadata = {
  device: deviceName,
  alarm_type: alarm.type,
  severity: alarm.severity,
  status: alarm.status,
  createdTime: alarm.createdTime
};

return msg;

// Αν είναι η πρώτη αποτυχία, αρχίζουμε το μέτρημα από το 0
if (msg.retries === undefined) {
    msg.retries = 0;
}

// Αν δεν έχουμε φτάσει ακόμα τις 3 προσπάθειες
if (msg.retries < 3) {
    msg.retries += 1;

    // Επειδή το Catch Node αλλάζει λίγο το msg.payload, 
    // επαναφέρουμε το αρχικό payload που περιέχει το JSON μας
    if (msg.error && msg.error.message) {
        node.warn("Αποτυχία MinIO (Προσπάθεια " + msg.retries + "/3): " + msg.error.message);
    }

    return [msg, null]; // Στέλνουμε το μήνυμα στην έξοδο 1 (προς το Delay)
} else {
    node.error("🚨 Το MinIO απέτυχε οριστικά μετά από 3 προσπάθειες!");
    return [null, msg]; // Στέλνουμε το μήνυμα στην έξοδο 2 (εδώ θα μπει ο Circuit Breaker μετά!)
}

// Κρατάμε μόνο το αρχικό payload που θέλαμε να αποθηκεύσουμε
let cleanMessage = {
    payload: msg.payload,
    customer: msg.customer,
    filename: msg.filename,
    objectName: msg.objectName,
    metadata: msg.metadata
};

return cleanMessage;
